mapper.select:
SELECT p.project_id AS "projectId", p.tenant_id AS "tenantId", p.project_code AS "projectCode", p.client_id AS "clientId", p.project_name AS "projectName", p.starts_on AS "startsOn", p.ends_on AS "endsOn", p.project_status AS "projectStatus", p.aggregate_version AS "aggregateVersion", p.created_at AS "createdAt", COALESCE((SELECT jsonb_agg(r.region_code ORDER BY r.region_code) FROM prj_project_region r WHERE r.tenant_id=p.tenant_id AND r.project_id=p.project_id AND r.valid_to IS NULL), '[]'::jsonb)::text AS "regionCodes", COALESCE((SELECT jsonb_agg(n.network_id ORDER BY n.network_id) FROM prj_project_network n WHERE n.tenant_id=p.tenant_id AND n.project_id=p.project_id AND n.valid_to IS NULL), '[]'::jsonb)::text AS "networkIds" FROM prj_project p WHERE p.tenant_id=#{tenantId}
AND p.project_id IN
CAST(#{projectId} AS uuid)
AND FALSE
AND p.client_id=#{clientId} AND p.project_status=#{status}
AND p.starts_on <=#{activeOn} AND (p.ends_on IS NULL OR p.ends_on >=#{activeOn})
AND (p.project_code, p.project_id) > (#{cursorCode}, #{cursorId})
ORDER BY p.project_code, p.project_id LIMIT #{fetchSize}
